import subprocess


# Each category defines a label, description, color for the UI,
# and a cmd factory that builds the journalctl command for a given line count.
CATEGORIES = {
    "system": {
        "label": "System",
        "description": "General system logs generated by systemd and core services.",
        "color": "#4ade80",
        "cmd": lambda n: ["journalctl", "-n", str(n), "--no-pager", "-o", "short"],
    },
    "kernel": {
        "label": "Kernel",
        "description": "Low-level kernel messages — hardware, drivers, and system errors.",
        "color": "#60a5fa",
        "cmd": lambda n: ["journalctl", "-k", "-n", str(n), "--no-pager", "-o", "short"],
    },
    "auth": {
        "label": "Auth",
        "description": "Authentication events, sudo usage and SSH — who logged in and when.",
        "color": "#fbbf24",
        "cmd": lambda n: ["journalctl", "-n", str(n), "--no-pager", "-o", "short", "-u", "sshd", "-u", "sudo", "_COMM=sudo"],
    },
    "boot": {
        "label": "Boot",
        "description": "Logs from the last system boot — startup sequence and errors.",
        "color": "#a78bfa",
        "cmd": lambda n: ["journalctl", "-b", "-n", str(n), "--no-pager", "-o", "short"],
    },
    "applications": {
        "label": "Applications",
        "description": "Logs from installed applications such as nginx, mysql, postgresql.",
        "color": "#f87171",
        "cmd": lambda n: ["journalctl", "-n", str(n), "--no-pager", "-o", "short", "_SYSTEMD_UNIT!=init.scope", "--system"],
    },
}


def get_log_categories() -> list:
    """
    Returns the list of available log categories for the UI.
    Each item contains id, label, description and color.
    """
    return [
        {"id": k, "label": v["label"], "description": v["description"], "color": v["color"]}
        for k, v in CATEGORIES.items()
    ]


def get_logs(category: str, lines: int = 100) -> dict:
    """
    Fetches the last N lines of logs for a given category using journalctl.

    Returns {"success": True, "lines": list of parsed log lines}
    or {"success": False, "error": str} on failure.
    """
    if category not in CATEGORIES:
        return {"success": False, "error": f"Unknown category: {category}"}

    cmd = CATEGORIES[category]["cmd"](lines)

    try:
        result = subprocess.run(
            cmd, capture_output=True, text=True, timeout=10
        )
        raw_lines = result.stdout.strip().splitlines()
        parsed = [_parse_line(l) for l in raw_lines if l.strip()]
        return {"success": True, "lines": parsed}
    except FileNotFoundError:
        return {"success": False, "error": "journalctl not found on this system."}
    except subprocess.TimeoutExpired:
        return {"success": False, "error": "Timeout while reading logs."}


def _parse_line(line: str) -> dict:
    """
    Parses a single journalctl log line into timestamp, message and level.
    Level is detected by keywords in the line (error, warn, etc.).

    Returns {"ts": str, "msg": str, "level": "info" | "warn" | "err"}.
    """
    level = "info"
    lower = line.lower()

    if "error" in lower or "failed" in lower or "err" in lower:
        level = "err"
    elif "warn" in lower or "warning" in lower:
        level = "warn"

    # journalctl short format: "Month Day HH:MM:SS hostname process: message"
    parts = line.split(None, 4)
    if len(parts) >= 5:
        ts = " ".join(parts[:3])
        msg = " ".join(parts[3:])
    else:
        ts = ""
        msg = line

    return {"ts": ts, "msg": msg, "level": level}